import React from "react";
import { useAuth } from "../context/AuthContext";
import { useWishlist } from "../context/WishlistContext";
import { useCart } from "../context/CartContext";

const Profile = () => {
  const { user, logout } = useAuth();
  const { wishlist, removeFromWishlist } = useWishlist();
  const { addToCart } = useCart();

  if (!user) {
    return (
      <div className="container py-5 text-center">
        <p>No estás autenticado. Por favor, inicia sesión.</p>
      </div>
    );
  }

  return (
    <div className="profile-page">
      <div className="container py-5">

        {/* Información del usuario */}
        <div className="profile-box mb-5">
          <h2 className="profile-title">Perfil</h2>

          <div className="profile-user-info">
            <p>
              <strong>Nombre:</strong> {user.nombre}
            </p>
          </div>

          <button className="btn profile-logout-btn" onClick={logout}>
            Cerrar sesión
          </button>
        </div>

        {/* Wishlist */}
        <div className="profile-box">
          <h3 className="profile-title mb-4">Mis deseados</h3>

          {wishlist.length === 0 ? (
            <p className="profile-empty-text">
              Aún no tienes productos guardados en tu lista de deseados.
            </p>
          ) : (
            <div className="row g-4">
              {wishlist.map((item) => (
                <div className="col-md-6 col-lg-4" key={item._id}>
                  <div className="profile-wishlist-card">

                    <img
                      src={item.image}
                      className="profile-wishlist-image"
                      alt={item.name}
                    />

                    <h5 className="profile-product-name">
                      {item.name}
                    </h5>

                    <p className="profile-product-price">
                      ${Number(item.price).toLocaleString("es-CL")}
                    </p>

                    <div className="d-grid gap-2">
                      <button
                        className="btn profile-cart-btn"
                        onClick={() => addToCart(item)}
                      >
                        Agregar al carrito
                      </button>

                      <button
                        className="btn profile-remove-btn"
                        onClick={() => removeFromWishlist(item._id)}
                      >
                        Quitar de deseados
                      </button>
                    </div>

                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

      </div>
    </div>
  );
};

export default Profile;
